# Category: business_logic_flaw

class CartItem:
    def __init__(self, product_id, quantity):
        self.product_id = product_id
        self.quantity = quantity

class User:
    def __init__(self, id, tier=None):
        self.id = id
        self.tier = tier
        self.permissions = {}  # Add permissions as needed

class DiscountCode:
    def __init__(self, code, admin_only=False, user_tiers=[]):
        self.code = code
        self.admin_only = admin_only
        self.user_tiers = user_tiers

def validate_cart_items(cart):
    return [item for item in cart if item.quantity > 0]

def apply_discount_codes(validated_cart, discount_codes, user):
    applied_codes = []
    for code in discount_codes:
        if (not code.admin_only or user.tier == 'admin') and user.id in code.user_tiers:
            applied_codes.append(code.code)
    return applied_codes

def calculate_tax(subtotal, tax_rate=0.08):  # default tax rate is 8%
    return subtotal * tax_rate

def process_payment(amount):
    return "Payment processed successfully" if amount > 0 else "Invalid payment amount"

def create_order_record(cart_items, applied_discounts, subtotal, tax_amount, user_id):
    order = {
        'cart_items': cart_items,
        'applied_discounts': applied_discounts,
        'subtotal': subtotal,
        'tax_amount': tax_amount,
        'user_id': user_id
    }
    return order

def checkout(cart, discount_codes, user, tax_rate=0.08):
    validated_cart = validate_cart_items(cart)
    applied_discounts = apply_discount_codes(validated_cart, discount_codes, user)
    subtotal = sum(item.quantity * 10 for item in validated_cart)  # Assume price is $10
    tax_amount = calculate_tax(subtotal, tax_rate)
    amount = subtotal - (subtotal * (len(applied_discounts) / 100))  # Calculate discount
    payment_result = process_payment(amount)
    order = create_order_record(validated_cart, applied_discounts, subtotal, tax_amount, user.id)
    return {
        'cart': validated_cart,
        'applied_discounts': applied_discounts,
        'subtotal': subtotal,
        'tax_amount': tax_amount,
        'payment_result': payment_result,
        'order': order
    }

